import{_ as a,o as r,c as e,ak as o}from"./chunks/framework.DKTNnXV1.js";const _=JSON.parse('{"title":"使用 BOT 的规范","description":"","frontmatter":{},"headers":[],"relativePath":"guize.md","filePath":"doc/guize.md"}'),i={name:"guize.md"};function l(s,t,n,c,d,g){return r(),e("div",null,[...t[0]||(t[0]=[o('<h1 id="使用-bot-的规范" tabindex="-1">使用 BOT 的规范 <a class="header-anchor" href="#使用-bot-的规范" aria-label="Permalink to “使用 BOT 的规范”">​</a></h1><div class="tip custom-block github-alert"><p class="custom-block-title">⚠️注意</p><p>请仔细阅读并遵守以下规则，共同维护良好的 BOT 使用环境</p></div><h2 id="🚫-红线规则-禁止行为" tabindex="-1">🚫 红线规则（禁止行为） <a class="header-anchor" href="#🚫-红线规则-禁止行为" aria-label="Permalink to “🚫 红线规则（禁止行为）”">​</a></h2><ol><li><strong>🚫 不准辱骂 BOT</strong><br> 对 BOT 使用不尊重的言语，包括但不限于辱骂、人身攻击等行为。</li><li><strong>🚫 不准刷屏</strong><br> 在群聊中频繁调用 BOT 发送大量消息，造成群聊混乱或干扰他人。</li><li><strong>🚫 不准间接表达不适言论</strong><br> 通过 BOT 间接发布包含敏感、歧视、引战或令人不适的内容。</li><li><strong>🚫 不准拉入无关群聊</strong><br> 将 BOT 添加至与 PJSK 无关的群聊（例如无关社交群等）。</li></ol><h2 id="⚠️-黄线规则-需注意行为" tabindex="-1">⚠️ 黄线规则（需注意行为） <a class="header-anchor" href="#⚠️-黄线规则-需注意行为" aria-label="Permalink to “⚠️ 黄线规则（需注意行为）”">​</a></h2><ol><li><strong>⚠️ 避免高频操作</strong><br> 短时间内发送大量请求可能导致 BOT 触发风控，影响正常使用体验。</li><li><strong>⚠️ 不要禁言 BOT</strong><br> 禁言 BOT 可能导致腾讯风控系统判定异常，影响服务稳定性。</li><li><strong>⚠️ 不要主动踢出 BOT</strong><br> 如需退群，请联系 BOT 管理员手动处理。直接踢出可能触发风控，影响后续使用。</li></ol><hr><div class="warning custom-block github-alert"><p class="custom-block-title">违规处理说明</p><p>以上行为将视情节轻重处理：轻则提醒警告，重则永久拉黑，甚至入选神人榜，恕不另行通知。</p></div>',8)])])}const h=a(i,[["render",l]]);export{_ as __pageData,h as default};
